// Pull out per-conjunct facts from each run's ensures. These are direct
// hypotheses (no fresh quantifier instantiation needed), so each assert
// is immediate.
assert(post1_self_.wf());
assert(post2_self_.wf());
assert(post1_self_.unique());
assert(post2_self_.unique());
assert(post1_self_.len() == pre_self_.len() + 1);
assert(post2_self_.len() == pre_self_.len() + 1);
assert(post1_self_.len() == post2_self_.len());
assert(post1_self_.get_node_ref(*new_value) == r1);
assert(post2_self_.get_node_ref(*new_value) == r2);

// View equality: both post states view to the same pushed sequence.
// Use Seq extensionality (`=~=`) to lift it to ==.
assert(post1_self_@ == pre_self_@.push(*new_value));
assert(post2_self_@ == pre_self_@.push(*new_value));
assert(post1_self_@ =~= post2_self_@);
assert(post1_self_@ == post2_self_@);

// Pointwise: for every v already in pre_self_@, both runs preserve
// pre_self_.get_node_ref(v), so post1 and post2 agree on it.
//
// Both ensures-foralls have `#![auto]` triggers; rather than re-asserting
// them under different triggers (which forced z3 to re-prove them from
// scratch in the previous attempt), instantiate them locally inside the
// `by` block by mentioning the trigger terms `post1_self_.get_node_ref(v)`
// and `post2_self_.get_node_ref(v)`.
assert forall|v: T| pre_self_@.contains(v) implies
    post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
    assert(pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
    assert(pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));
};
